INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '88a6a4d8-67f2-438c-8175-aff55240f748',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js Server vs Client Components — Push `use client` to the Leaves$escape$,
  $escape$By default, every component in the Next.js App Router is a Server Component — it renders on the server, has zero JS bundle impact, and can directly `await` database calls or read environment secrets. The mistake developers make is hoisting `'use client'` too high, converting entire subtrees to client components unnecessarily.

The pattern: keep layout shells, data-fetching wrappers, and static UI as Server Components. Only push `'use client'` down to the specific leaf that needs `useState`, `useEffect`, or browser APIs. A `<ProductPage>` that fetches data stays a Server Component — only its `<AddToCartButton>` child needs the directive.

This matters because `'use client'` marks a boundary: everything below it — including its imports — ships to the browser. A single misplaced directive on a parent can pull in heavy dependencies client-side that should never leave the server.

Use Next.js's `next/dynamic` with `{ ssr: false }` for third-party components that access `window` at import time, keeping the boundary explicit and intentional.$escape$,
  $escape$// app/products/[id]/page.tsx — Server Component (no directive)
import { AddToCartButton } from './AddToCartButton';
import { db } from '@/lib/db';

export default async function ProductPage({ params }: { params: { id: string } }) {
  const product = await db.product.findUnique({ where: { id: params.id } });
  return (
    <div>
      <h1>{product.name}</h1>
      <p>{product.description}</p>
      {/* Only this leaf is a Client Component */}
      <AddToCartButton productId={product.id} />
    </div>
  );
}

// app/products/[id]/AddToCartButton.tsx
'use client';
import { useState } from 'react';
export function AddToCartButton({ productId }: { productId: string }) {
  const [added, setAdded] = useState(false);
  return <button onClick={() => setAdded(true)}>{added ? 'Added!' : 'Add to Cart'}</button>;
}$escape$,
