INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '315964f3-d554-4b5c-ba63-32952decce08',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js State Management — URL as Truth for Filters and Pagination$escape$,
  $escape$Storing filters and pagination in `useState` is a common mistake in Next.js apps. It breaks deep-linking, loses state on refresh, and forces client-side fetching when the App Router already gives you a better primitive: the URL.

In the App Router, `searchParams` flows into every Server Component as a prop. A page like `/products?category=tools&page=2` gives you `{ category: 'tools', page: '2' }` at the server level — no `useEffect`, no loading spinner, no client bundle overhead. The data fetch happens in the Server Component using those params directly.

For client-side filter interactions, use `useRouter` and `useSearchParams` from `next/navigation`. Push new params with `router.push` or `router.replace` — the Server Component re-renders automatically with the updated URL. This makes every filter state shareable, bookmarkable, and crawlable by default.

Avoid `useState` for anything the server can own. If a value drives a data fetch, it belongs in the URL. Reserve `useState` for purely ephemeral UI state: open/close modals, hover states, uncontrolled input buffers.$escape$,
  $escape$// app/products/page.tsx — Server Component
type Props = { searchParams: { category?: string; page?: string } };

export default async function ProductsPage({ searchParams }: Props) {
  const { category = 'all', page = '1' } = searchParams;
  const products = await fetchProducts({ category, page: Number(page) });
  return <ProductList products={products} />;
}

// components/FilterBar.tsx — Client Component
'use client';
import { useRouter, useSearchParams } from 'next/navigation';

export function FilterBar() {
  const router = useRouter();
  const params = useSearchParams();

  const setCategory = (category: string) => {
    const next = new URLSearchParams(params.toString());
    next.set('category', category);
    next.set('page', '1'); // reset pagination on filter change
    router.push(`/products?${next.toString()}`);
  };

  return <button onClick={() => setCategory('tools')}>Tools</button>;
}$escape$,
  $escape$typescript$escape$,
