INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e3914567-a526-40b9-8c40-2a85550444ad',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js Rendering Modes — SSG vs SSR vs ISR Decision Matrix + Parallel Data Fetching$escape$,
  $escape$Pick the wrong rendering mode and you pay in either stale data or cold-start latency. The rule: default to SSG (`generateStaticParams` + no `dynamic` export), upgrade only when you need it. Use SSR (`export const dynamic = 'force-dynamic'`) only for pages requiring per-request data — auth-gated dashboards, personalized feeds. ISR (`revalidate: N`) hits the sweet spot for content that changes on a schedule: marketing pages, docs, leaderboards. Never use ISR for user-specific data — the cache is shared. For data fetching, Next.js 15 deduplicates `fetch` calls across the same render tree, but parallel fetching still matters. Inside `page.tsx` or a Server Component, fire independent `fetch` calls concurrently with `Promise.all` rather than awaiting them sequentially. Sequential awaits in a layout + page chain compound latency — each segment waits for the previous. Co-locate data fetching in the leaf component that needs it; React's request deduplication prevents over-fetching even when multiple components call the same endpoint.$escape$,
  $escape$// app/dashboard/page.tsx — parallel fetch, ISR with per-route revalidation
export const revalidate = 60; // ISR: revalidate every 60s

export default async function DashboardPage() {
  // Parallel — not sequential awaits
  const [metrics, activity] = await Promise.all([
    fetch('https://api.example.com/metrics', { next: { revalidate: 30 } }).then(r => r.json()),
    fetch('https://api.example.com/activity', { next: { tags: ['activity'] } }).then(r => r.json()),
  ]);

  return <Dashboard metrics={metrics} activity={activity} />;
}

// Force revalidate on demand via Server Action
import { revalidateTag } from 'next/cache';
export async function refreshActivity() { revalidateTag('activity'); }$escape$,
  $escape$typescript$escape$,
