INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9f2e8aca-e723-47c0-9601-10721c454ed2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js Data Fetching — Hoist Fetches to Server Components, Kill the Waterfall$escape$,
  $escape$Fetching data inside client components creates request waterfalls: the component renders, mounts, then fires a fetch. By the time the response arrives, the user has been staring at a spinner. Next.js App Router eliminates this with async Server Components — fetch runs on the server before any HTML reaches the client.

Make components async, await fetch directly at the top level, and pass data down as props. For parallel independent fetches, use Promise.all — Next.js deduplicates identical fetch calls within a single render pass via its built-in request memoization. For dynamic routes, generateStaticParams pre-renders pages at build time.

Avoid the pattern of fetching in useEffect inside a Client Component unless you explicitly need client-side revalidation (e.g., SWR or React Query for user-specific, real-time data). Even then, seed the initial data via a Server Component and pass it as initialData. Route-level fetches in layout.tsx run in parallel with page.tsx fetches — structure your tree to exploit this.$escape$,
  $escape$// app/posts/[id]/page.tsx
export default async function PostPage({ params }: { params: { id: string } }) {
  // Both fetches run in parallel — no waterfall
  const [post, comments] = await Promise.all([
    fetch(`https://api.example.com/posts/${params.id}`).then(r => r.json()),
    fetch(`https://api.example.com/posts/${params.id}/comments`).then(r => r.json()),
  ]);

  return (
    <>
      <h1>{post.title}</h1>
      <CommentList comments={comments} />
    </>
  );
}$escape$,
  $escape$typescript$escape$,
