INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '10738633-a3b8-4c70-9c4a-ec4180ea45a6',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js Server Actions — Forms, Progressive Enhancement & Server-Side Validation$escape$,
  $escape$Server Actions let you colocate mutation logic with your UI without building a separate API route. Attach one to a `<form>` via the `action` prop and Next.js handles the POST automatically — no `onSubmit`, no `fetch`. The critical detail: because the action runs on the server, validation lives there too. Use Zod inside the action, parse `formData`, and return structured errors. For progressive enhancement, pair this with `useActionState` (React 19 / Next.js 15) — the form works without JS, and when JS loads, you get optimistic UI and inline error display without a full page reload. Never trust client-side validation alone; the server action is the real trust boundary. Avoid revalidating the entire layout on every submission — call `revalidatePath` or `revalidateTag` with surgical precision. Mark the action file with `'use server'` at the top, or inline the directive inside an async function. Inlining inside a Client Component requires the file-level directive on a separate module.$escape$,
  $escape$// app/actions/create-post.ts
'use server'
import { z } from 'zod'
import { revalidatePath } from 'next/cache'

const schema = z.object({ title: z.string().min(3) })

export async function createPost(_prev: unknown, formData: FormData) {
  const result = schema.safeParse({ title: formData.get('title') })
  if (!result.success) return { errors: result.error.flatten().fieldErrors }
  await db.post.create({ data: result.data })
  revalidatePath('/posts')
  return { errors: null }
}

// app/posts/new/page.tsx (Client Component)
'use client'
import { useActionState } from 'react'
import { createPost } from '@/app/actions/create-post'

export default function NewPost() {
  const [state, action] = useActionState(createPost, { errors: null })
  return (
    <form action={action}>
      <input name="title" />
      {state.errors?.title && <p>{state.errors.title[0]}</p>}
      <button type="submit">Create</button>
    </form>
  )
}$escape$,
  $escape$typescript$escape$,
