INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f41cbb93-03ea-4c02-85af-bcd6c713d011',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js Error Boundaries — error.tsx, notFound(), and redirect() Per Route Segment$escape$,
  $escape$Next.js App Router scopes error handling to individual route segments via `error.tsx`. Drop one alongside a `page.tsx` and it becomes a React error boundary for that subtree only — sibling segments stay interactive. The component must be a Client Component (`'use client'`) and receives `error` and `reset` props; `reset()` re-renders the segment without a full page reload.

For data-layer errors, `notFound()` throws a special signal that Next.js catches and renders the nearest `not-found.tsx` — skip manual 404 responses entirely. `redirect()` from `next/navigation` works in Server Components, Route Handlers, and Server Actions; it throws internally, so wrap it outside try/catch blocks. In a Server Action, call `redirect()` after awaiting your mutation — Next.js handles the response automatically.

Global fallback lives in `app/error.tsx`; root-level crashes (layout errors) require `app/global-error.tsx`, which replaces the entire `<html>` shell since the root layout is compromised.$escape$,
  $escape$// app/dashboard/error.tsx
'use client'

export default function DashboardError({
  error,
  reset,
}: {
  error: Error & { digest?: string }
  reset: () => void
}) {
  return (
    <div>
      <p>Dashboard failed: {error.message}</p>
      <button onClick={reset}>Retry</button>
    </div>
  )
}

// app/dashboard/page.tsx (Server Component)
import { notFound, redirect } from 'next/navigation'

export default async function DashboardPage() {
  const user = await getUser()
  if (!user) redirect('/login')          // throws — no return needed
  if (!user.hasAccess) notFound()        // renders nearest not-found.tsx
  return <Dashboard user={user} />
}$escape$,
  $escape$typescript$escape$,
