INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a828b040-f305-4ea9-b7aa-a23493ddeb85',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js Testing — Isolate Server Actions and Route Handlers, Then Seal It with Playwright$escape$,
  $escape$Server Actions and Route Handlers in the App Router are plain async functions — import and call them directly in Vitest without spinning up a server. For Server Actions, pass a real `FormData` instance. For Route Handlers, construct a `NextRequest` with `new NextRequest('http://localhost/api/posts', { method: 'POST', body: JSON.stringify(payload) })` and invoke the exported `POST` function directly. The critical mocks are `next/headers` (`cookies`, `headers`) and `next/navigation` (`redirect`, `notFound`) — these are the trust boundaries where Next.js internals bleed into your logic. Mock them with `vi.mock` before any test imports your module.

Playwright covers what unit tests cannot: RSC streaming, middleware execution, client-side navigation after a Server Action redirect, and Suspense boundary resolution. Point Playwright at `next start` (production build), not `next dev`, to catch `generateStaticParams` misses and build-time errors. Use `test.use({ storageState: 'playwright/.auth/user.json' })` to inject Clerk session cookies for authenticated flows, generated once via `page.context().storageState()` in a global setup file. Assert on `page.url()` after form submission to validate redirect correctness end-to-end.$escape$,
  $escape$// __tests__/actions/create-post.test.ts
vi.mock('next/headers', () => ({ cookies: vi.fn(() => ({ get: vi.fn() })) }))
vi.mock('next/navigation', () => ({ redirect: vi.fn() }))
vi.mock('@/lib/db', () => ({ db: { post: { create: vi.fn() } } }))

import { createPost } from '@/app/actions/create-post'
import { db } from '@/lib/db'
import { redirect } from 'next/navigation'

it('persists post and redirects to slug', async () => {
  vi.mocked(db.post.create).mockResolvedValue({ slug: 'hello-nextjs' })
  const fd = new FormData()
  fd.set('title', 'Hello Next.js')
  await createPost(fd)
  expect(db.post.create).toHaveBeenCalledWith({ data: { title: 'Hello Next.js' } })
  expect(redirect).toHaveBeenCalledWith('/posts/hello-nextjs')
})$escape$,
  $escape$typescript$escape$,
