INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a77f5c93-1297-4e63-97ea-78280226c75e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js Server Actions Are Not Auto-Secure — Treat Them as Public API Endpoints$escape$,
  $escape$Server Actions feel internal, but every `'use server'` function is an exposed HTTP endpoint Next.js generates under `/_next/action`. Any client — including curl — can invoke them directly. Never assume the caller is your own UI.

Validate every input with Zod before touching the database or running business logic. Don't rely on client-side validation as a gate. A hidden form field or a raw fetch to the action URL bypasses your React form entirely.

Env var separation is equally critical. Variables prefixed `NEXT_PUBLIC_` are bundled into the client — never put secrets there. Database URLs, API keys, and signing secrets must be unprefixed and only accessed inside Server Actions or Route Handlers. Accidentally referencing `process.env.NEXT_PUBLIC_*` in an action is fine, but the reverse — a secret leaking into `NEXT_PUBLIC_*` — ships your key to every browser.

Also enforce authorization explicitly: `auth()` from Clerk (or your session provider) must be called at the top of every action. There is no framework-level guard — unauthenticated invocations reach your action body unless you stop them.$escape$,
  $escape$// app/actions/update-post.ts
'use server';

import { auth } from '@clerk/nextjs/server';
import { z } from 'zod';
import { db } from '@/lib/db';

const schema = z.object({
  postId: z.string().uuid(),
  title: z.string().min(1).max(120),
});

export async function updatePost(raw: unknown) {
  const { userId } = await auth();
  if (!userId) throw new Error('Unauthorized');

  const { postId, title } = schema.parse(raw); // throws on invalid input

  // process.env.DATABASE_URL is safe — no NEXT_PUBLIC_ prefix
  return db.post.update({ where: { id: postId, authorId: userId }, data: { title } });
}$escape$,
  $escape$typescript$escape$,
