INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cb5fbb1b-2085-4488-8fe8-3d14d937780a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js Route Segment Conventions — Naming Loaders and Actions for Maintainable Apps$escape$,
  $escape$Next.js App Router enforces file-based conventions (`page.tsx`, `layout.tsx`, `loading.tsx`, `error.tsx`), but inside those files naming discipline is entirely on you. Without consistent patterns, async data functions scatter into unmaintainable chaos across large route trees.

Adopt a strict convention: prefix Server Component data functions with `load` and Server Actions with `action`. For a route at `app/dashboard/posts/[id]/`, your `page.tsx` exports a default component that calls `loadPost(id)` — a local async function co-located in the same file or a sibling `loader.ts`. Mutations live in `actions.ts` alongside, exporting named functions like `actionUpdatePost` and `actionDeletePost`.

This mirrors the loader/action mental model from Remix but fits App Router's file conventions. Co-locating `loader.ts` and `actions.ts` per route segment keeps feature logic self-contained, makes parallel route refactors surgical (move the folder, done), and gives you instant grep-ability — `actionUpdate` always means a Server Action, never ambiguous. Pair with TypeScript's `use server` directive at the top of `actions.ts` to enforce the boundary.$escape$,
  $escape$// app/dashboard/posts/[id]/loader.ts
import { db } from '@/lib/db';

export async function loadPost(id: string) {
  return db.post.findUniqueOrThrow({ where: { id } });
}

// app/dashboard/posts/[id]/actions.ts
'use server';
import { db } from '@/lib/db';
import { revalidatePath } from 'next/cache';

export async function actionUpdatePost(id: string, title: string) {
  await db.post.update({ where: { id }, data: { title } });
  revalidatePath(`/dashboard/posts/${id}`);
}

// app/dashboard/posts/[id]/page.tsx
import { loadPost } from './loader';
import { actionUpdatePost } from './actions';

export default async function PostPage({ params }: { params: { id: string } }) {
  const post = await loadPost(params.id);
  return <PostEditor post={post} updateAction={actionUpdatePost} />;
}$escape$,
  $escape$typescript$escape$,
