INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0b91af52-dea2-44a9-b0c9-de7936a8fb03',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js Routing — Dynamic Segments, Catch-All, Parallel & Intercepting Routes$escape$,
  $escape$Next.js App Router maps the filesystem directly to URL segments. A folder named `[id]` creates a dynamic segment; `[[...slug]]` creates an optional catch-all that also matches the root. Parallel routes use named slots — `@modal` and `@feed` inside a layout both render simultaneously in the same viewport, each managing their own loading and error boundaries independently. This is how you build dashboard UIs with co-dependent panels without lifting state. Intercepting routes use the `(.)`, `(..)`, or `(...)` conventions to render a route in the current context while keeping the original URL intact — perfect for modal photo galleries that deep-link. The combination is powerful: a `@modal` slot with an intercepting route like `(..)photo/[id]` lets you open a photo in a modal from a feed, while direct navigation to `/photo/[id]` renders the full page. Layouts share state across both paths, so the background feed never unmounts.$escape$,
  $escape$// app/@modal/(.)photo/[id]/page.tsx
export default function PhotoModal({ params }: { params: { id: string } }) {
  return <Dialog photoId={params.id} />;
}

// app/layout.tsx
export default function RootLayout({
  children,
  modal,
}: {
  children: React.ReactNode;
  modal: React.ReactNode;
}) {
  return (
    <html>
      <body>
        {children}
        {modal}
      </body>
    </html>
  );
}$escape$,
  $escape$typescript$escape$,
