INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '23e020d2-8b3a-4dae-b933-19f018653a22',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js i18n — URL-Based Routing vs Cookie Locale, and Server-Side Detection$escape$,
  $escape$Next.js App Router handles i18n through middleware-driven URL prefixes — there's no built-in `i18n` config like Pages Router had. The recommended pattern: store locale in the URL (`/en/dashboard`, `/fr/dashboard`), detect it server-side in middleware, and redirect accordingly. This makes locale cacheable at the CDN level and shareable via URL.

Cookie-based locale skips the URL prefix — useful for apps where clean URLs matter — but breaks CDN caching since locale is invisible to the edge. You'd read `cookies().get('locale')` in a Server Component or middleware and render the appropriate translations without redirecting.

Server-side detection in middleware uses the `Accept-Language` header via `negotiator` + `@formatjs/intl-localematcher`. Match against your supported locales, fall back to default, then `NextResponse.redirect()` to the prefixed path. Use `matcher` to exclude static assets and API routes. For the App Router, locale lives in `params.lang` from a `[lang]` dynamic segment — pass it to your `getDictionary(lang)` server-side loader, never expose translation bundles to the client unnecessarily.$escape$,
  $escape$// middleware.ts
import { NextRequest, NextResponse } from 'next/server';
import Negotiator from 'negotiator';
import { match } from '@formatjs/intl-localematcher';

const locales = ['en', 'fr', 'de'];
const defaultLocale = 'en';

function getLocale(request: NextRequest): string {
  const headers = { 'accept-language': request.headers.get('accept-language') ?? '' };
  const languages = new Negotiator({ headers }).languages();
  return match(languages, locales, defaultLocale);
}

export function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl;
  const hasLocale = locales.some(l => pathname.startsWith(`/${l}/`) || pathname === `/${l}`);
  if (hasLocale) return;
  const locale = request.cookies.get('locale')?.value ?? getLocale(request);
  return NextResponse.redirect(new URL(`/${locale}${pathname}`, request.url));
}

export const config = { matcher: ['/((?!_next|api|favicon.ico).*)'] };$escape$,
  $escape$typescript$escape$,
