INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5e90d7c2-ceee-4a4f-8450-dda4bbc147dd',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js Web Vitals — Nail LCP with Image Optimization, Font Loading, and the priority Flag$escape$,
  $escape$LCP (Largest Contentful Paint) is almost always your hero image or above-the-fold text. Next.js gives you exact tools to fix both.

For images, swap `<img>` for `next/image`. It auto-generates `srcset`, serves WebP/AVIF via the built-in Image Optimization API, and lazy-loads by default. The critical addition: `priority` prop on your above-the-fold image. This injects a `<link rel="preload">` in the `<head>`, eliminating the waterfall delay that tanks LCP scores.

For fonts, use `next/font` — never load Google Fonts via a `<link>` tag. `next/font/google` downloads at build time, self-hosts on your domain, and injects `font-display: swap` automatically. Zero layout shift, zero third-party DNS lookup penalty.

Combine both: `priority` on `<Image>` ensures the browser fetches your hero before parsing the rest of the document; `next/font` ensures text renders immediately with the fallback, swapping when the font is ready. Together they routinely push LCP under the 2.5s Good threshold without any manual preload juggling.$escape$,
  $escape$import Image from 'next/image';
import { Inter } from 'next/font/google';

const inter = Inter({
  subsets: ['latin'],
  display: 'swap',   // next/font sets this automatically
});

export default function HeroSection() {
  return (
    <main className={inter.className}>
      <Image
        src="/hero.jpg"
        alt="Hero"
        width={1200}
        height={600}
        priority          // injects <link rel="preload"> — critical for LCP
        sizes="100vw"
      />
    </main>
  );
}$escape$,
  $escape$typescript$escape$,
