INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '22e72519-6a7d-40d8-b61b-52821db98767',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js Memory Leaks — Suspense Streaming, Abort Signals, and Navigation Cleanup$escape$,
  $escape$Three leak vectors bite Next.js apps in production. First, streaming Server Components: when Suspense boundaries flush chunks and the user navigates away, uncancelled upstream fetches keep running server-side. Inside Route Handlers, forward `request.signal` directly into every downstream `fetch()` — Next.js marks it aborted the moment the client disconnects, collapsing the entire call chain at zero cost.

Second, Client Components doing data fetching with `useEffect`: without an `AbortController`, the promise resolves and calls `setState` on an unmounted tree. In App Router, `<Link>` and `router.push()` unmount the previous page immediately, so this fires on every navigation. Attach `signal: ac.signal` to the fetch and return `() => ac.abort()` from the effect — that's the cleanup hook Next.js triggers on route change.

Third, anything outside React's lifecycle — `setInterval`, WebSocket connections, EventSource for server-sent events — won't auto-cancel. Store them in a `useRef` and tear them down in the same `useEffect` return. React's `use()` hook inside Suspense boundaries propagates abort correctly only when the underlying `fetch()` is wired with a signal in the first place.$escape$,
  $escape$// app/api/feed/route.ts — abort upstream on client disconnect
export async function GET(req: Request) {
  const upstream = await fetch('https://api.internal/feed', {
    signal: req.signal,
  });
  return Response.json(await upstream.json());
}

// components/feed-client.tsx — cancel on App Router navigation
'use client';
import { useEffect, useState } from 'react';

export function FeedClient() {
  const [items, setItems] = useState<{ id: string; title: string }[]>([]);
  useEffect(() => {
    const ac = new AbortController();
    fetch('/api/feed', { signal: ac.signal })
      .then(r => r.json())
      .then(setItems)
      .catch(err => { if (err.name !== 'AbortError') throw err; });
    return () => ac.abort();
  }, []);
  return <ul>{items.map(i => <li key={i.id}>{i.title}</li>)}</ul>;
}$escape$,
  $escape$typescript$escape$,
