INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2242d63a-b328-42b2-8946-31a8d967fd9f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js SSE — Streaming Server Events from Route Handlers into Client State$escape$,
  $escape$Next.js Route Handlers support Server-Sent Events natively via the Web Streams API. Return a `ReadableStream` with `Content-Type: text/event-stream` and Next.js will flush chunks as they arrive — no third-party library needed.

On the server, a `ReadableStream` wraps a controller that calls `enqueue()` for each event and `close()` when done. The `cache: 'no-store'` header prevents Next.js from buffering the response.

On the client, `EventSource` connects to the route and fires `onmessage` for each chunk. Wire this into `useState` inside a `useEffect` cleanup pattern: open the source on mount, push each parsed event into state, and call `source.close()` on unmount to avoid memory leaks.

Important gotcha: Next.js Edge Runtime handles SSE better than Node.js runtime for long-lived connections — add `export const runtime = 'edge'` to your route. For App Router, `dynamic = 'force-dynamic'` is also required to prevent static caching of the route segment.$escape$,
  $escape$// app/api/stream/route.ts
export const runtime = 'edge';
export const dynamic = 'force-dynamic';

export function GET() {
  const stream = new ReadableStream({
    async start(controller) {
      for (let i = 0; i < 5; i++) {
        controller.enqueue(`data: ${JSON.stringify({ tick: i })}\n\n`);
        await new Promise(r => setTimeout(r, 1000));
      }
      controller.close();
    },
  });
  return new Response(stream, {
    headers: { 'Content-Type': 'text/event-stream', 'Cache-Control': 'no-cache' },
  });
}

// hooks/useStream.ts
export function useStream(url: string) {
  const [events, setEvents] = useState<unknown[]>([]);
  useEffect(() => {
    const src = new EventSource(url);
    src.onmessage = (e) => setEvents(prev => [...prev, JSON.parse(e.data)]);
    return () => src.close();
  }, [url]);
  return events;
}$escape$,
  $escape$typescript$escape$,
