INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '72b359b6-6129-47f4-88e2-ee8680f7988d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js Environment Variables — NEXT_PUBLIC_ Prefix, Private Vars, and Startup Validation$escape$,
  $escape$Next.js splits environment variables at build time based on a single rule: the NEXT_PUBLIC_ prefix. Any variable prefixed with NEXT_PUBLIC_ gets inlined into the client bundle via static replacement — Webpack literally replaces process.env.NEXT_PUBLIC_API_URL with its string value. Strip the prefix and the variable stays server-only, accessible in Route Handlers, Server Components, getServerSideProps, and middleware, but undefined in the browser.

This means secrets like DATABASE_URL or STRIPE_SECRET_KEY must never carry the NEXT_PUBLIC_ prefix. If they do, they ship to every user's browser in plain text inside _next/static chunks.

The sharp edge: Next.js does not validate required variables by default. A missing NEXT_PUBLIC_API_URL silently becomes the string 'undefined' in the bundle. Fix this with a startup validation module — import it at the top of next.config.ts so the build fails fast before bad config reaches production. The @t3-oss/env-nextjs package wraps Zod and handles the NEXT_PUBLIC_ split automatically, erroring at both build time and runtime if variables are absent or malformed.$escape$,
  $escape$// env.ts — validated at build time via next.config.ts import
import { createEnv } from '@t3-oss/env-nextjs';
import { z } from 'zod';

export const env = createEnv({
  server: {
    DATABASE_URL: z.string().url(),
    STRIPE_SECRET_KEY: z.string().min(1),
  },
  client: {
    NEXT_PUBLIC_API_URL: z.string().url(),
    NEXT_PUBLIC_POSTHOG_KEY: z.string().min(1),
  },
  runtimeEnv: {
    DATABASE_URL: process.env.DATABASE_URL,
    STRIPE_SECRET_KEY: process.env.STRIPE_SECRET_KEY,
    NEXT_PUBLIC_API_URL: process.env.NEXT_PUBLIC_API_URL,
    NEXT_PUBLIC_POSTHOG_KEY: process.env.NEXT_PUBLIC_POSTHOG_KEY,
  },
});

// next.config.ts
import './env'; // throws at build time if any var is missing or invalid$escape$,
  $escape$typescript$escape$,
