INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c614a5cf-ad23-442f-9caf-af5033702c28',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js API Layer — Route Handlers, Server Actions, and Middleware Done Right$escape$,
  $escape$Next.js gives you three distinct primitives for your API layer, and mixing them up kills both DX and performance. Route Handlers (`app/api/*/route.ts`) are for public-facing REST endpoints — third-party webhooks, mobile clients, or any consumer outside your Next.js app. Export named HTTP methods (`GET`, `POST`) and return a `NextResponse`. Server Actions are for mutations triggered from your own UI. Decorated with `'use server'`, they run on the server, integrate with `useFormState`/`useTransition`, and automatically handle CSRF — no fetch boilerplate needed. Middleware (`middleware.ts`) runs on the Edge before any route resolves. Use it exclusively for auth checks, geo-redirects, and request rewriting — not for heavy data fetching. A common pattern: Middleware validates the Clerk JWT and sets a header; Server Actions read that header via `headers()` from `next/headers`; Route Handlers expose webhook endpoints consumed by Stripe or GitHub. Each primitive has a clear lane — crossing them introduces unnecessary latency or security gaps.$escape$,
  $escape$// middleware.ts — validate JWT, forward identity
import { clerkMiddleware, createRouteMatcher } from '@clerk/nextjs/server';

const isPublic = createRouteMatcher(['/api/webhooks(.*)']);

export default clerkMiddleware((auth, req) => {
  if (!isPublic(req)) auth().protect();
});

// app/api/webhooks/stripe/route.ts — public Route Handler
export async function POST(req: Request) {
  const body = await req.text();
  const sig = req.headers.get('stripe-signature')!;
  const event = stripe.webhooks.constructEvent(body, sig, process.env.STRIPE_SECRET!);
  await processEvent(event);
  return new Response('ok', { status: 200 });
}

// app/actions/post.ts — Server Action for UI mutations
'use server';
import { headers } from 'next/headers';

export async function createPost(formData: FormData) {
  const userId = headers().get('x-clerk-user-id');
  if (!userId) throw new Error('Unauthorized');
  await db.post.create({ data: { title: formData.get('title') as string, authorId: userId } });
}$escape$,
  $escape$typescript$escape$,
