INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3e76b2fb-bf1a-4d35-ba18-63544f0b1704',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js Global UI Patterns — Layout-Level Toast, Modal, and Shared Loading UI$escape$,
  $escape$Next.js App Router's layout segments are the natural home for global UI primitives. Place your ToastProvider and ModalProvider in app/layout.tsx once — every page inherits them without prop drilling. For scoped providers (e.g., dashboard-only toasts), use a route group layout like app/(dashboard)/layout.tsx to avoid polluting the root shell.

Loading states are more idiomatic still: colocate a loading.tsx next to any page.tsx and Next.js automatically wraps that segment in a <Suspense> boundary — no manual wrapping needed. The loading UI streams to the client instantly during navigation while the page's async Server Component fetches, then React flushes the real content when ready.

For modals, the @modal parallel route slot lets you render a modal alongside a page — the URL changes, the background page stays mounted, and closing it calls router.back(). This beats a global useState because modal state survives hard refreshes and is deep-linkable. Wire the slot into your segment layout alongside children and the three patterns compose cleanly into a navigation-aware UI shell — with zero extra client JS for the shell itself.$escape$,
  $escape$// app/(dashboard)/layout.tsx — scoped providers + @modal parallel slot
import { ToastProvider } from "@/components/ui/toast";
import { ModalProvider } from "@/components/ui/modal";

export default function DashboardLayout({
  children,
  modal,
}: {
  children: React.ReactNode;
  modal: React.ReactNode; // maps to app/(dashboard)/@modal/
}) {
  return (
    <ToastProvider>
      <ModalProvider>
        {children}
        {modal}
      </ModalProvider>
    </ToastProvider>
  );
}$escape$,
  $escape$typescript$escape$,
