INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9356e41e-a8d5-4398-8910-864f870dc0f8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js Bundle Optimization — Code Splitting, Dynamic Imports, and Analyzing What Ships$escape$,
  $escape$Next.js automatically code-splits at the route level — each file in `app/` or `pages/` becomes its own JS chunk, so users only download what the current route needs. But route-level splitting isn't enough for heavy third-party libs or rarely-used UI components.

Use `next/dynamic` to lazy-load components with an optional loading skeleton. Pass `ssr: false` for browser-only dependencies like chart libraries or rich text editors that touch `window` directly — this prevents SSR hydration errors and removes them from the server bundle entirely.

To inspect what you're actually shipping, add `@next/bundle-analyzer` to your config. Set `ANALYZE=true` before your build and it opens an interactive treemap showing chunk sizes, shared chunks (the `_app` bundle), and which modules are duplicated across routes.

Watch for: `moment.js` locale bloat (swap for `date-fns`), lodash full-bundle imports (use `lodash-es` with tree-shaking), and large icon sets imported as a barrel (`import * from 'lucide-react'` pulls everything — import individually instead).$escape$,
  $escape$// next.config.ts
import withBundleAnalyzer from '@next/bundle-analyzer';

const nextConfig = withBundleAnalyzer({
  enabled: process.env.ANALYZE === 'true',
})({
  // your existing config
});

export default nextConfig;

// app/dashboard/page.tsx
import dynamic from 'next/dynamic';

const HeavyChart = dynamic(() => import('@/components/HeavyChart'), {
  loading: () => <p>Loading chart...</p>,
  ssr: false,
});

export default function DashboardPage() {
  return <HeavyChart />;
}$escape$,
  $escape$typescript$escape$,
