INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a5bcc78f-f8f5-4533-83d1-5ce76e2141eb',
  '00000000-0000-0000-0000-000000000001',
  $escape$nextjs Typed Routes — Catch Broken Links and Bad Params at Build Time$escape$,
  $escape$Enable `experimental.typedRoutes: true` in `next.config.ts` and Next.js generates a `__next_route_internal_types__` declaration that maps every file in `app/` to a strongly-typed `Route` union. Once active, `Link href`, `router.push()`, and `redirect()` all accept only valid routes — typos become compile errors, not runtime 404s.

Route segment params are typed via the `Props` convention in App Router. Since Next.js 15, `params` is a `Promise<{ slug: string }>` — you must `await` it. Skipping the `await` causes a runtime error that `tsc` catches before deployment.

Wire this into your quality gate: `next build` runs `tsc` internally, but add `"typecheck": "tsc --noEmit"` to `package.json` scripts for faster CI feedback ahead of the build step. On Vercel, preview deployments run the full build pipeline — a type error on a feature branch blocks the preview URL and surfaces the failure directly in the PR check before any reviewer sees it.

`generateStaticParams` return types are inferred and checked against your `params` shape automatically, so mismatched segment names fail at compile time too.$escape$,
  $escape$// next.config.ts
import type { NextConfig } from 'next'
const config: NextConfig = { experimental: { typedRoutes: true } }
export default config

// app/blog/[slug]/page.tsx
type Props = { params: Promise<{ slug: string }> }

export async function generateStaticParams() {
  return [{ slug: 'hello-world' }, { slug: 'typed-routes' }]
}

export default async function BlogPost({ params }: Props) {
  const { slug } = await params   // must await in Next.js 15+
  return <h1>{slug}</h1>
}

// Elsewhere — typo in href is now a compile error
import Link from 'next/link'
;<Link href="/blog/hello-world">Post</Link>  // ✓
;<Link href="/blg/hello-world">Post</Link>   // ✗ TS2322$escape$,
  $escape$typescript$escape$,
