INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '185773a1-90c7-49fd-925e-a0f3420cf00c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Next.js Middleware — Edge Auth, A/B Testing, and Geo Routing Before First Byte$escape$,
  $escape$Next.js Middleware runs on the V8-based Edge Runtime — not Node.js — meaning no `fs`, no `net`, but sub-millisecond cold starts globally. Drop a `middleware.ts` at the project root and it intercepts every matched request before rendering begins.

The `matcher` config in `export const config` controls scope precisely — `['/dashboard/:path*']` keeps you from running auth logic on every static asset. Inside the function, `NextResponse.redirect()`, `.rewrite()`, and `.next()` are your three tools: redirect sends the user elsewhere, rewrite silently swaps the underlying route, and next forwards the request with optional header mutations.

For auth guards, read from `req.cookies` and call a lightweight JWT verify — no DB round-trips, keep it Edge-compatible. For A/B tests, read or set a bucketing cookie and pass the bucket via a request header (`x-ab-bucket`) so Server Components can read it via `headers()`. For geolocation, `req.geo?.country` is populated automatically on Vercel's edge network. Rate limiting requires an external store — use `@upstash/ratelimit`, which ships an Edge-compatible client.$escape$,
  $escape$import { NextRequest, NextResponse } from 'next/server';

export const config = { matcher: ['/dashboard/:path*'] };

export async function middleware(req: NextRequest) {
  const token = req.cookies.get('session')?.value;
  if (!token) return NextResponse.redirect(new URL('/login', req.url));

  const bucket = req.cookies.get('ab')?.value ?? (Math.random() < 0.5 ? 'a' : 'b');
  const res = NextResponse.next();
  res.cookies.set('ab', bucket, { httpOnly: true });
  res.headers.set('x-ab-bucket', bucket);

  if (req.geo?.country === 'DE')
    return NextResponse.rewrite(new URL('/de' + req.nextUrl.pathname, req.url));

  return res;
}$escape$,
  $escape$typescript$escape$,
